# New algorithm: {Select the next customer by prioritizing minimal waiting time and distance synergy among trucks with secondary consideration of urgency and historical delay.}

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_travel_time(pos1, pos2, speed):
        return np.linalg.norm(np.array(pos1) - np.array(pos2)) / speed

    def calculate_urgency(arrival_time, end_window):
        if arrival_time > end_window:
            return float('-inf')
        return 1.0 / (end_window - current_time) if end_window > current_time else float('inf')

    def calculate_waiting_potential(arrival_time, start_window):
        if arrival_time < start_window:
            return (start_window - arrival_time)
        return 0

    def calculate_historical_delay_potential(index):
        return 1.0 / (time_windows[index][1] - time_windows[index][0] + 1)

    best_node = None
    best_score = float('-inf')
    travel_weight = 0.2
    urgency_weight = 0.15
    waiting_weight = 0.4
    historical_delay_weight = 0.1
    multi_truck_distance_weight = 0.15

    for index, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_travel_time(cur_truck_pos, customer_pos, truck_speed)
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[index]

        travel_score = -travel_time
        urgency_score = calculate_urgency(arrival_time, end_window)
        waiting_score = -calculate_waiting_potential(arrival_time, start_window)
        historical_delay_score = -calculate_historical_delay_potential(index)
        multi_truck_distance_score = -sum(calculate_travel_time(truck_pos, customer_pos, truck_speed) for truck_pos in all_truck_pos) / len(all_truck_pos)

        score = (travel_weight * travel_score + 
                 urgency_weight * urgency_score + 
                 waiting_weight * waiting_score +
                 historical_delay_weight * historical_delay_score +
                 multi_truck_distance_weight * multi_truck_distance_score)

        if score > best_score:
            best_score = score
            best_node = index

    return best_node
